body.--blur-background:
color-mix(in srgb, hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	) 65%, transparent) linear-gradient(hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	), color-mix(in srgb, hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	) 65%, transparent))

body.--embed-block-shadow-hover:
0 0 0 1px hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	), inset 0 0 0 1px hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	)

body.--raised-background:
color-mix(in srgb, hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	) 65%, transparent) linear-gradient(hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	), color-mix(in srgb, hsl(
		from #181621 h calc(s + 3) calc(l + 4)
	) 65%, transparent))
